 1	import { MenuToggle, Select, SelectList, SelectOption } from '@patternfly/react-core';
 2	import { FilterIcon } from '@patternfly/react-icons';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { TopologyMetricPeer } from '../../../api/loki';
 6	import { Filter, FilterDefinition, Filters } from '../../../model/filters';
 7	import { NodeType } from '../../../model/flow-query';
 8	import { FilterDir, isDirElementFiltered, toggleDirElementFilter } from '../../../model/topology';
 9	import { useOutsideClickEvent } from '../../../utils/outside-hook';
10	import './summary-filter-button.css';
11	
12	export interface SummaryFilterButtonProps {
13	  id: string;
14	  filterType: NodeType;
15	  fields: Partial<TopologyMetricPeer>;
16	  filters: Filters;
17	  setFilters: (filters: Filter[]) => void;
18	  filterDefinitions: FilterDefinition[];
19	}
20	
21	const srcFilter: FilterDir = 'src';
22	const dstFilter: FilterDir = 'dst';
23	
24	export const SummaryFilterButton: React.FC<SummaryFilterButtonProps> = ({
25	  id,
26	  filterType,
27	  fields,
28	  filters,
29	  setFilters,
30	  filterDefinitions
31	}) => {
32	  const { t } = useTranslation('plugin__netobserv-plugin');
33	  const ref = useOutsideClickEvent(() => setOpen(false));
34	  const [isOpen, setOpen] = React.useState(false);
35	  const selected = [srcFilter, dstFilter].filter(dir =>
36	    isDirElementFiltered(filterType, fields, dir, filters.list, filterDefinitions)
37	  );
38	
39	  const onSelect = (dir: FilterDir, e?: React.BaseSyntheticEvent) => {
40	    toggleDirElementFilter(
41	      filterType,
42	      fields,
43	      dir,
44	      selected.includes(dir),
45	      filters.list,
46	      setFilters,
47	      filterDefinitions
48	    );
49	    if (e?.preventDefault) {
50	      e.preventDefault();
51	    }
52	  };
53	
54	  const menuItem = (id: FilterDir, label: string) => (
55	    <SelectOption id={id} key={id} value={id} hasCheckbox isSelected={selected.includes(id)}>
56	      {label}
57	    </SelectOption>
58	  );
59	
60	  return (
61	    <div id="summary-filters-dropdown-container" data-test="summary-filters-dropdown-container" ref={ref}>
62	      <Select
63	        isOpen={isOpen}
64	        toggle={toggleRef => (
65	          <MenuToggle
66	            ref={toggleRef}
67	            className="summary-filters-toggle"
68	            onClick={() => setOpen(!isOpen)}
69	            isExpanded={isOpen}
70	            variant="plain"
71	          >
72	            <FilterIcon />
73	          </MenuToggle>
74	        )}
75	        popperProps={{
76	          position: 'right'
77	        }}
78	        id={id}
79	        selected={selected}
80	        onSelect={(event, value) => value && onSelect(value as FilterDir, event)}
81	      >
82	        <SelectList className="summary-filters-list">
83	          {menuItem('src', filters.match === 'bidirectional' ? t('Endpoint A') : t('Source'))}
84	          {menuItem('dst', filters.match === 'bidirectional' ? t('Endpoint B') : t('Destination'))}
85	        </SelectList>
86	      </Select>
87	    </div>
88	  );
89	};

